import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, LayoutDashboard, Users, MessageCircle
} from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [userRequests, setUserRequests] = useState([]); 
  const [adminRequests, setAdminRequests] = useState([]);
  const [userCount, setUserCount] = useState(0);
  const [showModal, setShowModal] = useState(false);
  const [selectedFileName, setSelectedFileName] = useState("");

  // --- DATABASE SYNC ---
  const syncAdmin = async () => {
    const res = await axios.get('http://localhost:5000/api/admin/all');
    setAdminRequests(res.data.requests); // Pulls from Atlas
    setUserCount(res.data.usersCount);
  };

  const syncUser = async (id) => {
    const res = await axios.get(`http://localhost:5000/api/requests/user/${id}`);
    setUserRequests(res.data);
  };

  useEffect(() => {
    const role = localStorage.getItem('userRole');
    if (localStorage.getItem('token')) {
      if (role === 'admin') { setView('admin-dashboard'); syncAdmin(); }
      else { setView('dashboard'); syncUser(localStorage.getItem('userId')); }
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = (view === 'admin-login' || view === 'login') ? 'login' : 'register';
    const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
    if (mode === 'login') {
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('userRole', res.data.user.role);
      localStorage.setItem('userId', res.data.user._id);
      localStorage.setItem('userName', res.data.user.name);
      window.location.reload();
    } else { alert("Registered!"); setView('login'); }
  };

  // --- SAVING APPLICATION TO DATABASE ---
  const handleSubmission = async (e) => {
    e.preventDefault();
    const payload = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "uploaded_file.pdf"
    };
    await axios.post('http://localhost:5000/api/requests/submit', payload); // SAVES TO ATLAS
    alert("Application Saved to Database!");
    setShowModal(false);
    syncUser(localStorage.getItem('userId'));
    setActiveTab('tracking');
  };

  // --- ADMIN MODERATION (CLICKABLE STATUS CHANGE) ---
  const changeStatus = async (id, status) => {
    await axios.put(`http://localhost:5000/api/admin/status/${id}`, { status }); // UPDATES ATLAS
    alert(`Status Updated to ${status}`);
    syncAdmin();
  };

  const openPicker = async () => {
    const [fh] = await window.showOpenFilePicker();
    const f = await fh.getFile();
    setSelectedFileName(f.name);
  };

  if (['landing', 'login', 'register', 'admin-login'].includes(view)) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full">
            <h1 className="text-5xl font-black text-slate-900 mb-12 italic uppercase">QUAD SOLUTIONS</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition text-left">
                <UserPlus className="text-blue-600 mb-4" size={32} />
                <h2 className="text-2xl font-black">New Providers</h2>
                <div className="text-blue-600 font-bold mt-2">Get Started <ArrowRight className="inline ml-2" /></div>
              </div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition text-left">
                <LogIn className="text-blue-400 mb-4" size={32} />
                <h2 className="text-2xl font-black">Existing Clients</h2>
                <div className="text-blue-400 font-bold mt-2">Sign In <ArrowRight className="inline ml-2" /></div>
              </div>
            </div>
            <footer className="mt-20"><button onClick={() => setView('admin-login')} className="bg-white border px-6 py-2 rounded-full text-[10px] font-black uppercase text-slate-300 hover:text-blue-600 transition tracking-widest"><ShieldCheck className="inline mr-2" size={14}/> Internal Admin Access</button></footer>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 font-bold">Back</button>
            <h2 className="text-3xl font-black mb-8 italic uppercase underline decoration-blue-600 underline-offset-8">{view.replace('-', ' ')}</h2>
            <form onSubmit={handleAuth} className="space-y-4 text-left">
              {view === 'register' && <input type="text" placeholder="Name" className="w-full p-4 bg-slate-50 rounded-2xl font-bold" onChange={e => setFormData({...formData, name: e.target.value})} required />}
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl font-bold" onChange={e => setFormData({...formData, email: e.target.value})} required />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl font-bold" onChange={e => setFormData({...formData, password: e.target.value})} required />
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl">Continue</button>
            </form>
          </div>
        )}
      </div>
    );
  }

  // --- ADMIN VIEW (MODERATOR STYLE) ---
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white">
        <nav className="p-6 border-b border-slate-900 flex justify-between bg-black/40">
          <h1 className="text-xl font-black text-blue-500 uppercase italic">Admin Dashboard</h1>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold">Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-12">
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800"><p className="text-slate-500 font-black text-xs uppercase">Users</p><h4 className="text-4xl font-black">{userCount}</h4></div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800"><p className="text-slate-500 font-black text-xs uppercase">Total Files</p><h4 className="text-4xl font-black text-blue-500">{adminRequests.length}</h4></div>
           </div>
           <div className="bg-slate-900 rounded-[2rem] border border-slate-800 overflow-hidden shadow-2xl">
              <table className="w-full text-left">
                <thead className="bg-black/40 text-slate-500 text-[10px] font-black uppercase border-b border-slate-800">
                  <tr><th className="p-6">Provider</th><th className="p-6">Type</th><th className="p-6">File</th><th className="p-6">Status</th><th className="p-6 text-right">Moderation</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {adminRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition group">
                      <td className="p-6 font-black text-xs uppercase tracking-tighter">{req.userName}</td>
                      <td className="p-6 text-slate-400 text-xs italic">{req.type}</td>
                      <td className="p-6 text-blue-400 font-mono text-[10px] underline">{req.documentUrl}</td>
                      <td className="p-6">
                        <span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase ${req.status === 'Approved' ? 'bg-green-500 text-white' : 'bg-yellow-500 text-black'}`}>{req.status}</span>
                      </td>
                      <td className="p-8 text-right space-x-2">
                        <button onClick={() => changeStatus(req._id, 'Approved')} className="bg-green-600 text-white px-3 py-1 rounded-lg text-[9px] font-black uppercase">Approve</button>
                        <button onClick={() => changeStatus(req._id, 'Rejected')} className="bg-red-600/20 text-red-500 px-3 py-1 rounded-lg text-[9px] font-black border border-red-500/20 hover:bg-red-600 hover:text-white transition">Reject</button>
                      </td>
                    </tr>
                  ))}
                  {adminRequests.length === 0 && <tr><td colSpan="5" className="p-20 text-center text-slate-500 font-black italic uppercase">No applications in Database</td></tr>}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // --- USER VIEW ---
  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-white p-4 shadow-sm flex justify-between">
        <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
        <div className="flex gap-4">
           <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Services</button>
           <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Status</button>
           <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 p-2"><LogOut size={20}/></button>
        </div>
      </nav>
      <main className="p-10 max-w-5xl mx-auto">
        {activeTab === 'services' ? (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase underline decoration-blue-600 underline-offset-8">Available Services</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map(t => (
                <div key={t} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition group">
                   <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 mb-6 group-hover:bg-blue-600 group-hover:text-white transition-colors"><FileText/></div>
                   <h3 className="text-xl font-bold mb-4 tracking-tighter">{t}</h3>
                   <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-black uppercase text-[10px] hover:bg-blue-600 transition">Apply Now</button>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase tracking-tighter">My Application Status</h2>
            <div className="space-y-4">
               {userRequests.map((r, i) => (
                 <div key={r._id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex justify-between items-center shadow-sm hover:shadow-md transition">
                    <div className="flex items-center gap-6">
                        <div className="w-14 h-14 bg-slate-900 rounded-2xl flex flex-col items-center justify-center text-white"><span className="text-lg font-black italic">0{i+1}</span></div>
                        <div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter italic">{r.type}</h3><p className="text-slate-400 font-bold text-[9px] uppercase tracking-widest mt-1">Status: {r.status}</p></div>
                    </div>
                    <div className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest ${r.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-blue-100 text-blue-600'}`}>{r.status}</div>
                 </div>
               ))}
            </div>
          </div>
        )}
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 animate-in zoom-in">
            <h2 className="text-2xl font-black mb-8 text-blue-600 uppercase italic">New Submission</h2>
            <form onSubmit={handleSubmission} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-none outline-none"><option>Medical License</option><option>Insurance Enrollment</option></select>
              <input type="text" placeholder="License / NPI ID" className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none" required />
              <div onClick={openPicker} className="p-10 bg-blue-50 border-2 border-dashed border-blue-200 rounded-[2rem] cursor-pointer text-center group hover:bg-blue-100 transition">
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={32}/>
                <p className="text-[10px] font-black uppercase text-blue-600 tracking-tighter">{selectedFileName || "Select Document"}</p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl">Submit to Database</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full mt-2 text-slate-300 font-bold">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
